refsection.programlisting:
inputImage = imread(fullpath(getIPCVpath() + "/images/opencv_left01.jpg"));
inputImage = imresize(rgb2gray(inputImage), [120 160]);
guide = imread(fullpath(getIPCVpath() + "/images/opencv_left02.jpg"));
guide = imresize(rgb2gray(guide), [120 160]);
filtered = imguidedfilter(inputImage, guide, 4, 0.01);
subplot(1, 3, 1);
imshow(inputImage);
subplot(1, 3, 2);
imshow(guide);
subplot(1, 3, 3);
imshow(filtered);
